import React from 'react';
import styles from './mega-menu.module.css';

interface MegaMenuProps {
  dropDownObject: any[]; 
  show: boolean;
}

const MegaMenu: React.FC<MegaMenuProps> = ({ dropDownObject, show }) => {
  return (
    <div className={`${styles.megMenu__container} ${show && styles.show}`}>
      <div className="container">
        <ul className={`${styles.megaMenu__content} ${styles.listContainer}`}>
          {dropDownObject &&
            dropDownObject.map((listItem, index) => (
              <li key={index} data-object={listItem}>
                {listItem}
              </li>
            ))}
        </ul>
      </div>
    </div>
  );
}

export default MegaMenu;
